import { IMenuItemV2 } from '@src/mx-components/menu-item/mx-menu-item-v2/mx-menu-item-v2.model';

export interface IVirtualizationData {
  startIndex: number;
  length: number;
  paddingTop: number;
  paddingBottom: number;
  overallHeight: number;
}

// this function calculates how many items to render in the visible window and also top and bottom paddings
// for the inner items container
const calculateVirtualizationData = (
  items: IMenuItemV2[],
  containerHeight: number,
  currentScrollTop: number,
  calculateItemHeight: (iem: IMenuItemV2) => number,
  itemsPerRow = 1): IVirtualizationData => {
  const scrollBottom = currentScrollTop + containerHeight;
  let startIndex = NaN;
  let length = NaN;
  let paddingTop = currentScrollTop;
  let visibleItemsHeight = 0;
  let allItemsHeight = 0;
  items.forEach((item: IMenuItemV2, index: number) => {
    if (index % itemsPerRow === 0) {
      const isOnTopEdge: boolean = currentScrollTop >= allItemsHeight &&
        currentScrollTop <= allItemsHeight + calculateItemHeight(item);
      const isOnBottomEdge: boolean = scrollBottom >= allItemsHeight &&
        scrollBottom <= allItemsHeight + calculateItemHeight(item);

      if (isOnTopEdge && isNaN(startIndex)) {
        startIndex = index;
        paddingTop = allItemsHeight;
      }

      if (!isNaN(startIndex) && isNaN(length) ) {
        visibleItemsHeight += calculateItemHeight(item);
      }

      const isLastItem: boolean = index + itemsPerRow >= items.length;

      if (isNaN(length) && (isOnBottomEdge || isLastItem)) {
        length = index - startIndex + itemsPerRow;
      }

      allItemsHeight += calculateItemHeight(item);
    }
  });

  return {
    startIndex,
    length: length === 0 ? 1 : length,
    paddingTop,
    paddingBottom: allItemsHeight - paddingTop - visibleItemsHeight,
    overallHeight: allItemsHeight
  };
};

export { calculateVirtualizationData };
