import { Component, Element, Event, EventEmitter, h, Method, Prop, State, Watch } from '@stencil/core';
import {
  CustomKeysV2,
  IMenuItemV2,
  IMenuItemV2Entry,
  IMenuItemV2CurrentState,
  IMenuItemV2State,
  MenuItemV2Map,
  MenuItemV2StateMap,
  defaultMenuItemState,
  IMenuItemV2Props
} from '@src/mx-components/menu-item/mx-menu-item-v2/mx-menu-item-v2.model';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString } from '@src/utils/mx-utils/utils';
import { calculateVirtualizationData, IVirtualizationData } from '@src/utils/mx-utils/virtualization.utils';
import itemUtils from '@src/utils/mx-utils/mx-menu-item.utils';

type SearchTree = { _itemsPaths?: number[][] } & { [key: string]: SearchTree; };

type MenuItemV2MapObject = { [key: string]: MenuItemV2Map };

@Component({
  tag: 'mx-menu-item-v2-list',
  styleUrl: 'mx-menu-item-v2-list.css'
})
export class MxMenuItemV2List {

  @Element() hostEl: HTMLMxMenuItemV2ListElement;

  /*--------------------------------------------------------------------------------------------------------properties*/
  /** Sets items list. */
  @Prop() readonly items: IMenuItemV2[] | string[] = [];
  /** Sets an array of items that are currently selected. */
  @Prop() readonly selectedItems: IMenuItemV2[] | string[] = []; // this field for angular value accessor
  /** Sets the query. */
  @Prop() readonly query: string = '';
  /** Determines if there is 'select all' option.  */
  @Prop() readonly canSelectAll: boolean = true;
  /** Sets label for 'Select All' option. */
  @Prop() readonly selectAllLabel: string = 'Select all';
  /** Sets label if there are no results found.  */
  @Prop() readonly noResultsLabel: string = 'No Results Found';
  /** Sets compact flag to 'select all' option. */
  @Prop() readonly serviceItemsCompact: boolean = false;
  /** Sets showCheckbox flag for string items.  */
  @Prop() readonly showCheckboxForStringItems: boolean = true;
  /** Sets showCheckbox flag for all items.
   * Critical not to set default value here. */
  @Prop() readonly showCheckbox: boolean;
  /** Should the query be case-sensitive. */
  @Prop() readonly queryCaseSensitive: boolean = false;
  /** Sets css class to highlight passed query if it is found in label. */
  @Prop() readonly queryCssClass: string = 'text-brand-less-prominent';
  /** If true fixes errors in the input object:
   * 1. Sets selected to the children if parent is selected.
   * 2. Sets selected/indeterminate for parent according to children state.
   * 3. Sets indeterminate to false if it was true and selected was true.
   * 4. Ignore 'indeterminate' if the item has no children. */
  @Prop() readonly fixInput: boolean = false;
  /** Sets custom keys. */
  @Prop() readonly customKeys: CustomKeysV2 = { key: '', value: '' };
  /** Enables virtual scrolling. */
  @Prop() readonly enableVirtualScroll: boolean = false;
  /** Sets compact for each item.
   * Critical not to set default value here. */
  @Prop() readonly compactCheckbox: boolean;

  /*------------------------------------------------------------------------------------------------------------states*/
  /** Stores current list of items that should be present in the list. */
  @State() processedItems: IMenuItemV2[] = [];
  /** Object that stores items info, with all its structures flattened and accessible by key,
   * witch is now the value of the item. Also, it tracks all the item state. */
  @State() itemsMapObject: MenuItemV2MapObject = {};
  /** 'Select all' item model. */
  @State() selectAllItem: IMenuItemV2 = {
    label: this.selectAllLabel,
    value: 'select-all',
    showCheckbox: true,
    compactCheckbox: this.serviceItemsCompact,
    selected: false,
    indeterminate: false
  };

  /** Stores items container scrolling position. */
  @State() private itemsContainerScrollTop = 0;

  /** Stores the selected/indeterminate state of each item by its value.
   * We need this state because each query change we rerender items */
  @State() selectedItemsMap: MenuItemV2StateMap = {};

  /** We need to store this flag because if some item is disabled the select all item will remain indeterminate forever
   * and we will not be able to determine what action to perform on 'select all' click. */
  @State() fakeSelectedAll = false;

  /*-----------------------------------------------------------------------------------------------------------watches*/
  @Watch('items')
  onItemsChange(): void {
    this.composeProcessedItems();
    this.composeItemsMapObjectFromProcessedItems();
  }

  @Watch('selectedItems')
  onSelectedItemsChange(newSelectedItems: IMenuItemV2[] | string[]): void {
    this.selectedItemsMap = itemUtils.composeItemsStateMap(newSelectedItems, this.customKeys);
    this.composeProcessedItems();
    this.composeItemsMapObjectFromProcessedItems();
  }

  @Watch('query')
  onQueryChange(query: string): void {
    this.searchItems(query, itemUtils
      .convertStringItemsArrayToObjectsArray(this.items, this.compactCheckbox, this.showCheckboxForStringItems));
    this.itemsContainerRef && (this.itemsContainerRef.scrollTop = 0);
  }

  /*------------------------------------------------------------------------------------------------------------events*/
  /** Emitted when the user selects a menu item. Emits the menu item selected. */
  @Event() itemSelected: EventEmitter<IMenuItemV2CurrentState>;
  /** Emitted when the user selects a menu item. Emits all the items selected. */
  @Event() itemsSelected: EventEmitter<{ selectedItems: IMenuItemV2[] | string[] }>;
  /** Emitted when height has been changed. Emits the current height. */
  @Event() heightChanged: EventEmitter<{ height: number }>;

  /*-----------------------------------------------------------------------------------------------------------methods*/
  /** Deselect single item. */
  @Method()
  public async unselectSingleItem(
    item: IMenuItemV2,
    superParentId: string): Promise<{ selectedItems: IMenuItemV2[] | string[] }> {
    return new Promise((resolve) => {
      const value: string = itemUtils.hasCustomKeys(this.customKeys) ? item[this.customKeys.value] : item.value;
      const itemMap: MenuItemV2Map = this.itemsMapObject[superParentId];
      if (itemMap != null) {
        let key = 'root';
        let itemEntry: IMenuItemV2Entry = itemMap[key];
        if (itemEntry != null) {
          if (value !== itemEntry.value) {
            key = value;
            itemEntry = itemMap[value];
          }
          if (!itemEntry.disabled) {
            itemMap[key].selected = false;
          }
          itemUtils.goUpSelectedIndeterminate(itemEntry.parentId, itemMap);
          this.itemsMapObject = { ...this.itemsMapObject, [superParentId]: itemMap };
        }
        this.countAndUpdateSelectedAllItem();
      }
      if (!item.disabled) {
        if (!this.touchedFlatItemsMap.hasOwnProperty(value)) {
          this.touchedFlatItemsMap[value] = { ...defaultMenuItemState };
        }
        this.touchedFlatItemsMap[value].selected = false;
        this.touchedFlatItemsMap[value].indeterminate = false;
      }
      resolve({ selectedItems: this.composeSelectedList() });
    });
  }

  /** Deselect all items. */
  @Method()
  public async unselectAllItems(): Promise<{ selectedItems: IMenuItemV2[] | string[] }> {
    return new Promise((resolve) => {
      this.items.forEach((item: IMenuItemV2 | string) => {
        item = itemUtils.convertStringToItem(item, this.serviceItemsCompact, this.showCheckboxForStringItems);
        const value: string = itemUtils.hasCustomKeys(this.customKeys) ? item[this.customKeys.value] : item.value;
        const itemMap: MenuItemV2Map = itemUtils.composeItemMap(item,
          this.customKeys,
          this.selectedItemsMap,
          this.touchedFlatItemsMap,
          'root',
          this.composePropsToOverride());
        const itemMapFromObject: MenuItemV2Map = this.itemsMapObject[value];

        const itemMapRoot: IMenuItemV2Entry = itemMap['root'];
        const itemMapFromObjectRoot: IMenuItemV2Entry = itemMapFromObject['root'];
        const selectedOrIndeterminate: boolean = itemMapRoot.selected ||
          itemMapRoot.indeterminate ||
          itemMapFromObjectRoot.selected ||
          itemMapFromObjectRoot.indeterminate;

        if (!itemMapRoot.disabled && selectedOrIndeterminate) {
          Object.keys(itemMap).forEach((key: string) => {
            if (!itemMap[key].disabled) {
              if (itemMap[key].children.length === 0 && itemMap[key].selected) {
                if (!this.touchedFlatItemsMap.hasOwnProperty(key)) {
                  this.touchedFlatItemsMap[key] = { ...defaultMenuItemState };
                }
                this.touchedFlatItemsMap[key].selected = false;
                this.touchedFlatItemsMap[key].indeterminate = false;
              }
              itemMap[key].selected = false;
              itemMap[key].indeterminate = false;
            }
          });
          itemUtils.validateAndFixInput(itemMap);
          this.touchedFixedFullItemsMap[value] = itemMap;
          this.itemsMapObject[value] = itemMap;
        }
      });
      this.countAndUpdateSelectedAllItem();
      resolve({ selectedItems: this.composeSelectedList() });
    });
  }

  /*----------------------------------------------------------------------------------------------------private-fields*/
  // Utility object (prefix tree) that stores ifo about the items list for a quick search through the items.
  private searchTree: SearchTree = {};
  // height of the items list
  private listHeight = 0;
  // A reference to the item's container. used to set scroll top when needed
  private itemsContainerRef: HTMLDivElement | null = null;

  // this 2 fields stores touched items state - we need that because itemsMapObject contains only visible objects,
  // so if selected item became invisible we will lose its state
  private touchedFlatItemsMap: MenuItemV2StateMap = {};
  private touchedFixedFullItemsMap: MenuItemV2MapObject = {};

  private readonly minListHeight: number = 320;
  private readonly minVisibleItems: number = 8;

  /*---------------------------------------------------------------------------------------component-lifecycle-methods*/
  componentWillLoad(): void {
    this.selectedItemsMap = itemUtils.composeItemsStateMap(this.selectedItems, this.customKeys);
    this.composeProcessedItems();
    this.composeItemsMapObjectFromProcessedItems();
  }

  /*------------------------------------------------------------------------------------------------------------render*/
  render() {
    const showSelectAll = this.canSelectAll && this.processedItems.length > 0;
    const itemsNotFound = this.processedItems.length === 0 && this.query !== '';
    let paddingTop = 0;
    let paddingBottom = 0;
    let overallHeight = 'auto';
    let items: IMenuItemV2[] = this.processedItems;
    if (this.enableVirtualScroll) {
      const virtualizationData: IVirtualizationData = calculateVirtualizationData(
        this.processedItems,
        this.listHeight,
        this.itemsContainerScrollTop,
        (item: IMenuItemV2) => {
          const value: string = itemUtils.hasCustomKeys(this.customKeys) ? item[this.customKeys.value] : item.value;
          return this.calculateItemHeight(this.itemsMapObject[value], 'root');
        });
      const startIndex: number = virtualizationData.startIndex;
      const lastIndex: number = startIndex + virtualizationData.length;
      paddingTop = virtualizationData.paddingTop;
      paddingBottom = virtualizationData.paddingBottom;
      overallHeight = virtualizationData.overallHeight + 'px';
      items = items.slice(startIndex, lastIndex);
    }

    return <ul class='mx-menu-item-v2-list'>
      {
        showSelectAll ? <div>
          <mx-menu-item-v2
            item={this.selectAllItem}
            onItemSelected={this.selectAllItemSelectedHandler.bind(this)}/>
          <hr class='mx-menu-item-v2-list__divider'/>
        </div> : ''
      }

      {
        itemsNotFound ? <mx-menu-item-v2
          item={{
            label: this.noResultsLabel,
            value: 'no-results',
            compactCheckbox: this.serviceItemsCompact,
            showCheckbox: false
          }}
        /> : <div
          class='overflow-y-auto'
          style={{ overflowAnchor: 'none', height: this.listHeight + 'px' }}
          ref={(ref: HTMLDivElement  ) => {
            this.itemsContainerRef = ref;
          }}
          onScroll={(event: UIEvent) => {
            if (this.enableVirtualScroll) {
              this.itemsContainerScrollTop = (event.target as HTMLDivElement).scrollTop;
            }
          }}>
          <div style={{ paddingTop: paddingTop + 'px', paddingBottom: paddingBottom + 'px', height: overallHeight }}>
            {
              items.map((item: IMenuItemV2, index: number) => {
                const value: string = itemUtils.hasCustomKeys(this.customKeys) ?
                  item[this.customKeys.value] :
                  item.value;
                const itemMap: MenuItemV2Map = this.itemsMapObject[value];
                return <mx-menu-item-v2
                  key={index}
                  itemMap={{ ...itemMap }}
                  fixInput={false}
                  query={this.query}
                  queryCaseSensitive={this.queryCaseSensitive}
                  queryCssClass={this.queryCssClass}
                  customKeys={this.customKeys}
                  onItemSelected={this.itemSelectedHandler.bind(this)}
                  onItemDisplayChildrenChanged={this.itemDisplayChildrenChangeHandler.bind(this)}
                />;
              })
            }
          </div>
        </div>
      }
    </ul>;
  }

  /*---------------------------------------------------------------------------------------------------private-methods*/
  private itemSelectedHandler(event: CustomEvent<IMenuItemV2CurrentState>): void {
    this.updateItemMapObject(event.detail);
    const fixedStateMap: MenuItemV2Map = event.detail.fixedStateMap;
    this.touchedFixedFullItemsMap[fixedStateMap['root'].value] = fixedStateMap;
    Object.keys(fixedStateMap).forEach((key: string) => {
      if (key!== 'root' && fixedStateMap[key].children.length === 0) {
        this.touchedFlatItemsMap[key] = {
          selected: fixedStateMap[key].selected,
          displayChildren: fixedStateMap[key].displayChildren
        };
      }
    });
    this.countAndUpdateSelectedAllItem();
    this.itemsSelected.emit({ selectedItems: this.composeSelectedList() });
  }

  private itemDisplayChildrenChangeHandler(event: CustomEvent<IMenuItemV2CurrentState>) {
    this.updateItemMapObject(event.detail);
    this.itemsMapObject = { ...this.itemsMapObject };
  }

  private updateItemMapObject(state: IMenuItemV2CurrentState): void {
    const fixedStateMap: MenuItemV2Map = state.fixedStateMap;
    this.itemsMapObject[fixedStateMap['root'].value] = fixedStateMap;
  }

  private selectAllItemSelectedHandler(): void {
    this.fakeSelectedAll = !this.fakeSelectedAll;
    const selected: boolean = this.fakeSelectedAll;
    let selectedCount = 0;
    let indeterminateCount = 0;
    this.processedItems = this.processedItems.map((item: IMenuItemV2) => {
      const value: string = itemUtils.hasCustomKeys(this.customKeys) ? item[this.customKeys.value] : item.value;
      let itemMap: MenuItemV2Map = this.itemsMapObject[value];
      let root: IMenuItemV2Entry = itemMap['root'];
      if (!root.disabled) {
        root.selected = selected;
        root.indeterminate = false;
        itemMap = itemUtils.updateSelectedItemInMap('root', selected, itemMap);
      }
      root = itemMap['root'];
      if (root.selected) {
        selectedCount++;
      }
      if (root.indeterminate) {
        indeterminateCount++;
      }
      this.itemsMapObject[value] = itemMap;
      this.touchedFixedFullItemsMap[value] = itemMap;
      Object.keys(itemMap).forEach((key: string) => {
        if (itemMap[key].children.length === 0) {
          this.touchedFlatItemsMap[itemMap[key].value] = {
            selected: itemMap[key].selected,
            displayChildren: itemMap[key].displayChildren
          };
        }
      });
      return item;
    });
    this.updateSelectedAllItem(selectedCount, indeterminateCount, false);
    this.itemsSelected.emit({ selectedItems: this.composeSelectedList() });
  }

  private composeProcessedItems(): void {
    this.processedItems = itemUtils
      .convertStringItemsArrayToObjectsArray(this.items, this.compactCheckbox, this.showCheckboxForStringItems);
    this.searchTree = {};
    this.composeSearchTree(this.processedItems, this.searchTree, []);

    if (!isNullOrUndefinedOrEmptyString(this.query)) {
      this.searchItems(this.query, this.processedItems);
    }

    this.updateListHeight();
  }

  private composeItemsMapObjectFromProcessedItems(): void {
    let selectedCount = 0;
    let indeterminateCount = 0;
    this.processedItems.forEach((item: IMenuItemV2) => {
      const value: string = itemUtils.hasCustomKeys(this.customKeys) ? item[this.customKeys.value] : item.value;
      const selItemState: IMenuItemV2State = this.selectedItemsMap[value];
      if (selItemState) {
        item.selected = selItemState.selected;
      }
      const updatedItemState: IMenuItemV2State = this.touchedFlatItemsMap[value];
      if (updatedItemState) {
        item.selected = updatedItemState.selected;
        item.displayChildren = updatedItemState.displayChildren;
      }
      const itemMap: MenuItemV2Map = itemUtils.composeItemMap(
        item,
        this.customKeys,
        this.selectedItemsMap,
        this.touchedFlatItemsMap,
        'root',
        this.composePropsToOverride());
      if (this.itemsMapObject.hasOwnProperty(value)) { // merge state only for items without children
        const existingItemMap: MenuItemV2Map = this.itemsMapObject[value];
        [...Object.keys(itemMap)].forEach((key: string) => {
          const itemEntry: IMenuItemV2Entry = itemMap[key];
          if (itemEntry.children.length === 0 && existingItemMap.hasOwnProperty(key)) {
            const existingItemMapEntry: IMenuItemV2Entry = existingItemMap[key];
            itemMap[key] = { ...existingItemMapEntry, children: itemEntry.children };
          }
        });
      }
      if (this.fixInput) {
        itemUtils.validateAndFixInput(itemMap);
      }
      this.itemsMapObject[value] = itemMap;

      const root: IMenuItemV2Entry = itemMap['root'];
      if (root.selected) {
        selectedCount++;
      }
      if (root.indeterminate) {
        indeterminateCount++;
      }
    });

    this.updateSelectedAllItem(selectedCount, indeterminateCount);

    this.itemsMapObject = { ...this.itemsMapObject };
  }

  // this function recursively creates data structure called 'prefix tree' from the given items labels (or from custom key if defined)
  // after created - the tree looks like an object with fields are letters of the items
  // For Example if items will be these:
  // const items = [
  //   { label: 'Dog', value: 'dog', children: [ { label: 'Cat', value: 'cat' } ] },
  //   { label: 'Dog2', value: 'dog2' },
  //   { label: 'Dog3', value: 'dog3' },
  // ];
  // The result tree will be:
  // let searchTree = {
  //       c: {
  //         a: {
  //           t: { _itemsPaths: [0, 0] }
  //         }
  //       },
  //       d: {
  //         o: {
  //           g: {
  //             2: { _itemsPaths: [1] },
  //             3: { _itemsPaths: [2] },
  //             _itemsPaths: [0]
  //           }
  //         }
  //       }
  //     };
  // '_itemsPaths' field is present only if the letter is the end of the item label and
  // contains path to the element in the original items.
  // (There can be multiple items ends on this letter, so it is an array of paths)
  // It is array each item represents the index of the element in original array.
  // And the length of this array represents how deep items is nested in the original structure.
  private composeSearchTree(items: IMenuItemV2[], searchTree: SearchTree, path: number[]): void {
    if (isNullOrUndefined(items) || items.length === 0) {
      return;
    }
    let searchBy = 'label';
    if (itemUtils.hasCustomKeys(this.customKeys)) {
      searchBy = this.customKeys.key;
    }
    items.forEach((item: IMenuItemV2, itemIndex: number) => {
      let currentNode: SearchTree = searchTree;
      const currentPath: number[] = [...path, itemIndex];
      item[searchBy].split('').forEach((letter: string, letterIndex: number) => {
        letter = this.queryCaseSensitive ? letter : letter.toLowerCase();
        const isLastLetter: boolean = letterIndex === item[searchBy].length - 1;
        const letterExists: boolean = currentNode.hasOwnProperty(letter);
        if (isLastLetter && !letterExists) {
          currentNode[letter] = {};
          currentNode[letter]._itemsPaths = [currentPath];
        } else if (isLastLetter && letterExists) {
          currentNode[letter]._itemsPaths.push(currentPath);
        } else if (!isLastLetter && !letterExists) {
          currentNode[letter] = {};
        }
        currentNode = currentNode[letter];
      });
      this.composeSearchTree(item.children, searchTree, currentPath);
    });
  }

  // To search items in a 'prefix tree' structure you simply iterate through the given query trying to find letter sequence in the tree
  // This algorithm gives you O(n) complexity where 'n' is the length of the query. (Not depends on the given length of the items!)
  private searchItems(query: string, items: IMenuItemV2[]): void {
    if (isNullOrUndefinedOrEmptyString(query)) {
      this.processedItems = items;
      this.composeItemsMapObjectFromProcessedItems();
      return;
    }

    query = this.queryCaseSensitive ? query : query.toLowerCase();

    const foundNodes: SearchTree[] = [];
    this.search(this.searchTree, foundNodes, query);

    const itemsIndexes = {};
    foundNodes.forEach((node: any) => this.fillItemIndexesFromSearchTreeNode(itemsIndexes, node));

    const foundItems: IMenuItemV2[] = [];

    this.fillFoundItems(itemsIndexes, this.items, foundItems);

    this.processedItems = foundItems;
    this.composeItemsMapObjectFromProcessedItems();
  }

  private search(node: SearchTree, foundNodes: SearchTree[], query: string): void {
    if (node != null) {
      Object.keys(node).forEach((key: string) => {
        if (this.queryCaseSensitive ? key === query[0] : key.toLowerCase() === query[0].toLowerCase()) {
          this.checkNode(node[key], query.substring(1), foundNodes, query);
        } else {
          if (key !== '_itemsPaths') {
            this.search(node[key], foundNodes, query);
          }
        }
      });
    }
  }

  private checkNode(node: SearchTree, query: string, nodes: SearchTree[], fullQuery: string): void {
    let currentNode = node;
    if (query === '') {
      nodes.push(currentNode);
      return;
    }

    for (let i = 0; i < query.length; i++) {
      const letter: string = query[i];
      const key: string = this.queryCaseSensitive ? letter : letter.toLowerCase();
      if (currentNode.hasOwnProperty(key)) {
        currentNode = currentNode[letter];
        if (i === query.length - 1) {
          nodes.push(currentNode);
        }
      } else {
        this.search(node, nodes, fullQuery);
        return;
      }
    }
  }

  private fillFoundItems(itemsIndexes, items: IMenuItemV2[] | string[], foundItems: IMenuItemV2[]): void {
    if (Object.keys(itemsIndexes).length === 0 || items.length === 0) {
      return;
    }
    Object.keys(itemsIndexes).forEach((index: string) => {
      let children = [];
      const item: IMenuItemV2 = itemUtils.convertStringToItem(
        items[index],
        this.serviceItemsCompact,
        this.showCheckboxForStringItems
      );
      if (Object.keys(itemsIndexes[index]).length > 0) {
        this.fillFoundItems(itemsIndexes[index], item.children, children);
      } else {
        if (item && item.children) {
          children = item.children.map((ch: IMenuItemV2) => {
            return { ...ch, children: [] };
          });
        }
      }
      const foundItem = { ...item, children };
      foundItems.push(foundItem);
    });
  }

  private fillItemIndexesFromSearchTreeNode(itemsIndexes, node: any): void {
    Object.keys(node).forEach((key: string) => {
      if (key === '_itemsPaths') {
        node._itemsPaths.forEach((itemPath: number[]) => {
          this.fillItemsIndexesFromArrayOfIndexes(itemsIndexes, itemPath);
        });
      } else {
        this.fillItemIndexesFromSearchTreeNode(itemsIndexes, node[key]);
      }
    });
  }

  private fillItemsIndexesFromArrayOfIndexes(itemsIndexes, itemPath: number[]) {
    if (itemPath.length > 0) {
      const parentIndex = itemPath[0];
      if (!itemsIndexes.hasOwnProperty(parentIndex)) {
        itemsIndexes[parentIndex] = {};
      }
      this.fillItemsIndexesFromArrayOfIndexes(itemsIndexes[parentIndex], itemPath.slice(1));
    }
  }

  private composeSelectedList(): IMenuItemV2[] {
    const selectedItems: IMenuItemV2[] = [];
    this.items.forEach((item: IMenuItemV2 | string) => {
      if (typeof item === 'string') {
        item = itemUtils.convertStringToItem(item, this.serviceItemsCompact, this.showCheckboxForStringItems);
      }
      const itemMap: MenuItemV2Map = itemUtils.composeItemMap(
        item,
        this.customKeys,
        this.selectedItemsMap,
        this.touchedFlatItemsMap,
        'root',
        this.composePropsToOverride());
      itemUtils.validateAndFixInput(itemMap);
      if (itemMap != null) {
        const root: IMenuItemV2Entry = itemMap['root'];
        if (root.selected || root.indeterminate) {
          selectedItems.push({
            ...item,
            selected: root.selected,
            indeterminate: root.indeterminate,
            children: itemUtils.composeSelectedChildren(item.children, itemMap, this.customKeys)
          });
        }
      }
    });
    return selectedItems;
  }

  private countAndUpdateSelectedAllItem(): void {
    let selectedCount = 0;
    let indeterminateCount = 0;
    this.processedItems.forEach((item: IMenuItemV2) => {
      const value: string = itemUtils.hasCustomKeys(this.customKeys) ? item[this.customKeys.value] : item.value;
      const itemMap: MenuItemV2Map = this.itemsMapObject[value];
      const root: IMenuItemV2Entry = itemMap['root'];
      if (root.selected) {
        selectedCount++;
      }
      if (root.indeterminate) {
        indeterminateCount++;
      }
    });

    this.updateSelectedAllItem(selectedCount, indeterminateCount);
  }

  private updateSelectedAllItem(
    selectedCount: number,
    indeterminateCount: number,
    updateFakeSelectedAll = true): void {
    const selected: boolean = this.processedItems.length > 0 && selectedCount === this.processedItems.length;
    const indeterminate: boolean = !selected && (selectedCount > 0 || indeterminateCount > 0);
    this.selectAllItem = { ...this.selectAllItem, selected, indeterminate };
    if (updateFakeSelectedAll) {
      this.fakeSelectedAll = selected;
    }
  }

  private updateListHeight(): void {
    if (isNullOrUndefined(this.processedItems)) {
      return;
    }
    const length: number = this.getItemsLength(this.processedItems); // amount of all items including all children
    const itemHeight: number = this.getItemHeight(); // height of a single item
    const totalItemHeight: number = length * itemHeight; // height of all items
    let height: number = length <= this.minVisibleItems ? totalItemHeight : this.minListHeight;
    this.listHeight = height;
    if (this.canSelectAll) { // adding height of the select all item
      height += (itemHeight + 2); //we also need to add height of the divider
    }
    this.heightChanged.emit({ height });
  }

  private getItemsLength(items: IMenuItemV2[]): number {
    const itemsCount = items.reduce((acc: number, item: IMenuItemV2) => {
      acc += 1;
      const displayChildren: boolean = item.hasOwnProperty('displayChildren') ? item.displayChildren : true;
      if (item.children && displayChildren) {
        acc += this.getItemsLength(item.children);
      }
      return acc;
    }, 0);
    return itemsCount + (this.canSelectAll && itemsCount > 0 ? 1 : 0);
  }

  private getItemHeight(): number {
    return this.compactCheckbox ? 32 : 34;
  }

  private calculateItemHeight(itemMap: MenuItemV2Map, id: string): number {
    const singleItemHeight: number = this.getItemHeight();
    const item: IMenuItemV2Entry = itemMap[id];
    if (item.displayChildren && item.children && item.children.length > 0) {
      return item.children.reduce((acc: number, child: string) => {
        return acc + this.calculateItemHeight(itemMap, child);
      }, singleItemHeight);
    } else {
      return singleItemHeight;
    }
  }

  private composePropsToOverride() {
    const propsToOverride: IMenuItemV2Props = {};
    if (this.showCheckbox != null) {
      propsToOverride.showCheckbox = this.showCheckbox;
    }
    if (this.compactCheckbox != null) {
      propsToOverride.compactCheckbox = this.compactCheckbox;
    }
    return propsToOverride;
  }
}
